# --- 2. HYDRA ENGINE ---
def get_hydra_w3():
    endpoints = [os.getenv("RPC_URL"), "https://polygon-rpc.com", "https://1rpc.io/matic"]
    for url in endpoints:
        if not url: continue
        try:
            _w3 = Web3(Web3.HTTPProvider(url.strip()))
            if _w3.is_connected():
                _w3.middleware_onion.inject(ExtraDataToPOAMiddleware, layer=0)
                return _w3
        except: continue
    return None

w3 = get_hydra_w3()
ERC20_ABI = [{"constant": True, "inputs": [{"name": "_owner", "type": "address"}], "name": "balanceOf", "outputs": [{"name": "balance", "type": "uint256"}], "type": "function"}]
usdc_e_contract = w3.eth.contract(address=USDC_E, abi=ERC20_ABI)

def get_vault():
    seed = os.getenv("WALLET_SEED", "").strip()
    Account.enable_unaudited_hdwallet_features()
    return Account.from_mnemonic(seed) if " " in seed else Account.from_key(seed)

vault = get_vault()

def init_clob():
    client = ClobClient(host="https://clob.polymarket.com", key=vault.key.hex(), chain_id=137, signature_type=int(os.getenv("SIGNATURE_TYPE", 0)), funder=vault.address)
    client.set_api_creds(client.create_or_derive_api_creds())
    return client

clob_client = init_clob()

# --- 3. THE "ALWAYS FIND" ARBITRAGE ENGINE ---
# This ensures even if ROI is negative, we see the 'best' available efficiency.
def calculate_arbitrage_guaranteed(p_yes, p_no, total_capital):
    combined_prob = p_yes + p_no
    if combined_prob <= 0: return None
    
    # Calculate stakes to ensure equal payout on both sides
    stake_yes = (p_no / combined_prob) * total_capital
    stake_no = (p_yes / combined_prob) * total_capital
    
    # Expected payout per cycle
    expected_payout = (stake_yes / p_yes) 
    profit = expected_payout - total_capital
    roi = (profit / total_capital) * 100

    return {
        "stake_yes": round(stake_yes, 2),
        "stake_no": round(stake_no, 2),
        "profit": round(profit, 2),
        "roi": round(roi, 2),
        "efficiency": round(combined_prob, 4)
    }

async def fetch_full_market(cond_id):
    try:
        url = f"https://clob.polymarket.com/markets/{cond_id}"
        r = await asyncio.to_thread(requests.get, url, timeout=5)
        d = r.json()
        tokens = {t['outcome'].upper(): {"id": t['token_id'], "price": float(t['price'])} for t in d.get('tokens', [])}
        return tokens if 'YES' in tokens and 'NO' in tokens else None
    except: return None

async def scour_all_markets():
    global ARBI_CACHE
    ARBI_CACHE = []
    # Expanded tag list: Politics, Crypto, Sports, Business, Science, Health
    tags = [1, 10, 100, 4, 6, 237]
    
    tasks = []
    for tag in tags:
        url = f"https://gamma-api.polymarket.com/events?active=true&closed=false&limit=20&tag_id={tag}"
        tasks.append(asyncio.to_thread(requests.get, url, timeout=5))
    
    responses = await asyncio.gather(*tasks, return_exceptions=True)
    
    for resp in responses:
        if isinstance(resp, Exception) or resp.status_code != 200: continue
        for e in resp.json():
            markets = e.get('markets', [])
            if not markets: continue
            
            m_data = await fetch_full_market(markets[0]['conditionId'])
            if m_data:
                p_y, p_n = m_data['YES']['price'], m_data['NO']['price']
                if p_y <= 0 or p_n <= 0: continue
                
                arb = calculate_arbitrage_guaranteed(p_y, p_n, 100.0)
                if arb:
                    ARBI_CACHE.append({
                        "title": e.get('title')[:25],
                        "yes_id": m_data['YES']['id'], "no_id": m_data['NO']['id'],
                        "p_y": p_y, "p_n": p_n,
                        "roi": arb['roi'],
                        "eff": arb['efficiency']
                    })

    # Sort by Efficiency (Lowest sum of Yes+No is best)
    ARBI_CACHE.sort(key=lambda x: x['eff'])
    return len(ARBI_CACHE) > 0

# --- 4. UI HANDLERS ---
async def start(update, context):
    btns = [['🚀 DEEP SCAN', '📊 CALIBRATE'], ['💳 VAULT', '🔄 REFRESH']]
    await update.message.reply_text(f"{LOGO}\n<b>OMNI-SCANNER ACTIVE</b>", reply_markup=ReplyKeyboardMarkup(btns, resize_keyboard=True), parse_mode='HTML')

async def main_handler(update, context):
    cmd = update.message.text
    if 'DEEP SCAN' in cmd or 'REFRESH' in cmd:
        m = await update.message.reply_text("🔎 <b>PIERCING ORDERBOOKS...</b>", parse_mode='HTML')
        if await scour_all_markets():
            # Show top 8 most efficient markets
            kb = []
            for i, a in enumerate(ARBI_CACHE[:8]):
                label = f"{'🟢' if a['roi'] > 0 else '🟡'} {a['title']} ({a['roi']}%)"
                kb.append([InlineKeyboardButton(label, callback_data=f"ARB_{i}")])
            
            await m.edit_text("<b>MOST EFFICIENT TARGETS:</b>", reply_markup=InlineKeyboardMarkup(kb), parse_mode='HTML')
        else:
            await m.edit_text("❌ <b>SCAN FAILED. CHECK API/RPC.</b>")

    elif 'VAULT' in cmd:
        e_bal = await asyncio.to_thread(usdc_e_contract.functions.balanceOf(vault.address).call)
        await update.message.reply_text(f"<b>VAULT</b>: ${e_bal/1e6:.2f} USDC.e", parse_mode='HTML')

async def handle_query(update, context):
    q = update.callback_query; await q.answer()
    stake = float(context.user_data.get('stake', 50))

    if "ARB_" in q.data:
        target = ARBI_CACHE[int(q.data.split("_")[1])]
        calc = calculate_arbitrage_guaranteed(target['p_y'], target['p_n'], stake)
        msg = (f"<b>TARGET:</b> {target['title']}\n"
               f"<b>ROI:</b> {calc['roi']}%\n\n"
               f"🔵 YES: ${calc['stake_yes']} @ {target['p_y']}\n"
               f"🔴 NO: ${calc['stake_no']} @ {target['p_n']}")
        kb = [[InlineKeyboardButton("🔥 EXECUTE DUAL-STRIKE", callback_data=f"EXE_{q.data.split('_')[1]}")]]
        await q.edit_message_text(msg, reply_markup=InlineKeyboardMarkup(kb), parse_mode='HTML')

    elif "EXE_" in q.data:
        target = ARBI_CACHE[int(q.data.split("_")[1])]
        calc = calculate_arbitrage_guaranteed(target['p_y'], target['p_n'], stake)
        # Execution logic follows (same as previous stable version)
        await context.bot.send_message(q.message.chat_id, "🚀 <b>ORDERS SENT</b>")

if __name__ == "__main__":
    app = ApplicationBuilder().token(os.getenv("TELEGRAM_BOT_TOKEN")).build()
